"""
MKT Context Commentary — Psalms chapters 105–106
Run: python3 scripts/zc-context-psalms-105-106.py

Key decisions in this range:
- Ps 105 and 106 form a matched diptych: grace (105) / unfaithfulness (106)
- Ps 105:1-15 closely parallels 1 Chr 16:8-22 (David's prayer at ark installation)
- The "anointed ones" and "prophets" in Ps 105:15 = the patriarchs in their context
- Joseph narrative in Ps 105 (vv. 16-22): providential reversal paradigm, word-tested-him motif
- Ps 106:20 "exchanged their glory": Paul quotes in Rom 1:23 for universal idolatry
- Phinehas intercession (Ps 106:30): counted as righteousness — cited in 1 Macc 2:26; Sir 45:23-24
- Ps 106 ends with post-exilic restoration prayer — Psalter final form context
- Both psalms open and close with Hallelujah / Hallelu-Yah
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "105": {
    "1": '<p>Psalm 105 opens a matched pair with Ps 106 — two great historical retrospectives placed side by side to form a diptych: YHWH\'s unbroken faithfulness (105) alongside Israel\'s unbroken unfaithfulness (106). Both open and close with "Praise the LORD" (<em>hallĕlû-yāh</em>). Psalm 105:1-15 is also found in 1 Chr 16:8-22, the prayer David composed when the ark was brought to Jerusalem — its liturgical use at that defining moment suggests it became a foundational recitation of covenant history. The opening summons ("Give thanks to the LORD, call on his name") combines two primary acts of covenant worship: <em>tôdāh</em> (thanksgiving) and <em>qārāʾ</em> (calling on the name, invoking his presence). "Make known his deeds among the peoples" — the horizontal dimension of praise: YHWH\'s acts in history are not private information but public testimony.</p>',
    "2": '<p>"Sing to him, sing praises to him; tell of all his wondrous works" — the threefold summons (<em>šîrû</em>, <em>zammĕrû</em>, <em>śîḥû</em>) covers the three modes of musical praise: singing (<em>šîr</em>), playing/singing (<em>zimmer</em>), and telling/meditating aloud (<em>śîaḥ</em>). "His wondrous works (<em>niplĕʾôtāyw</em>)" — the standard term for the mighty acts of God in history, especially the plagues and Exodus. In Second Temple Judaism, retelling the <em>niplĕʾôt</em> was an act of covenant loyalty — children were taught to recite them (Ps 78:4; Deut 6:20-25), and the Passover Haggadah structures this recitation as the central act of remembrance.</p>',
    "3": '<p>"Glory in his holy name; let the hearts of those who seek the LORD rejoice" — "glory in his name (<em>hithallĕlû bĕšēm qāḏšô</em>)" is the exact phrase Paul quotes in 1 Cor 1:31 and 2 Cor 10:17 (via Jer 9:24): "Let the one who boasts, boast in the Lord." The name (<em>šēm</em>) is the covenantal self-disclosure of YHWH — to glory in the name is to find one\'s identity and status in YHWH\'s character rather than in one\'s own achievements. "Those who seek the LORD (<em>mĕbaqqĕšê YHWH</em>)" — the covenantal category of those who actively orient themselves toward divine presence (cf. Amos 5:4-6: "Seek me and live").</p>',
    "4": '<p>"Seek the LORD and his strength; seek his presence (<em>pānāyw</em>) continually" — the double summons to seek both strength (<em>ʿuz</em>) and face (<em>pānîm</em>). In the covenantal framework, "seeking the face" of the king was the formal act of accessing royal presence and protection (cf. 2 Sam 14:24, 28, 32; 21:1 where "seeking the face of YHWH" is an oracular inquiry). The continuous, repeated (<em>tāmîd</em>) nature of the seeking distinguishes covenant relationship from transactional worship. The logic of the verse: divine strength is accessed through divine presence, not through independent human effort.</p>',
    "5": '<p>"Remember the wondrous works he has done, his miracles, and the judgments he pronounced" — the act of remembering (<em>zākar</em>) is not passive recollection but active appropriation of past divine acts as present reality. In the Passover liturgy (Deut 16:3; Exod 12:14), remembrance creates continuity between the original Exodus participants and every subsequent generation: "You shall remember that you were a slave in Egypt." The three-part formula — wondrous works (<em>niplĕʾôtāyw</em>), miracles (<em>môpĕtāyw</em>), and judgments (<em>mišpĕṭê-pîw</em>) — covers the full range of divine action in history: creation wonders, covenant-confirming signs, and legal pronouncements.</p>',
    "6": '<p>"O seed of Abraham, his servant, O children of Jacob, his chosen ones" — the address to the covenant community draws the two central patriarchal lineages into one: Abraham as <em>ʿebed</em> (servant, the same title applied to Moses and David in highest honor — Deut 34:5; 2 Sam 3:18) and Jacob as <em>bĕḥîrāyw</em> (chosen ones). The "chosen" language (<em>bāḥar</em>) is the key covenantal election verb (Deut 7:6: "the LORD your God has chosen you out of all the peoples"). Both titles — servant and chosen — define identity not through achievement but through relationship: you are who you are because of what YHWH did in choosing your ancestors.</p>',
    "7": '<p>"He is the LORD our God; his judgments are in all the earth" — the pivot from summons (vv. 1-6) to theological claim. "The LORD our God" (<em>YHWH ʾĕlōhênû</em>) is the standard covenant confessional formula (Deut 6:4 — the Shema begins "YHWH our God, YHWH is one"). "His judgments (<em>mišpāṭāyw</em>) are in all the earth" extends the claim from Israel\'s local deity to the God of universal jurisdiction. In the ANE theological framework, each people had their own god whose authority was limited to their territory. Ps 105 asserts YHWH\'s authority is geographically unlimited — his <em>mišpāṭîm</em> govern all nations.</p>',
    "8": '<p>"He has remembered his covenant forever, the word he commanded, for a thousand generations" — "a thousand generations" (<em>ʾelep dôr</em>) is the hyperbolic expression of permanence (Deut 7:9 uses the same phrase). The verse asserts the absolute durability of the Abrahamic covenant. "The word he commanded" — the covenant has the force of divine command (<em>ṣāwāh</em>), not merely a mutual agreement. "He has remembered (<em>zākar</em>)" — the same verb used of the Noah covenant (Gen 8:1 — "God remembered Noah") and the Exodus covenant (Exod 2:24 — "God remembered his covenant with Abraham"). Divine remembering is always followed by divine acting.</p>',
    "9": '<p>"The covenant he made with Abraham, the oath he swore to Isaac" — two of the three forms in which the Abrahamic covenant was communicated: covenant (<em>bĕrît</em>) with Abraham (Gen 15; 17) and oath (<em>šĕbûʿāh</em>) to Isaac (Gen 26:3-5). The distinction between covenant and oath is significant: a covenant could theoretically be renegotiated; an oath invoked YHWH\'s own existence as guarantee. The oath-character of the Abrahamic promise is emphasized in Heb 6:13-18 (the author of Hebrews grounds Christian assurance in the impossibility of divine oath-breaking).</p>',
    "10": '<p>"He confirmed it to Jacob as a statute, to Israel as an everlasting covenant" — the Abrahamic covenant\'s extension to Jacob is presented as both <em>ḥōq</em> (statute, binding regulation, similar to a royal decree) and <em>bĕrît ʿôlām</em> (everlasting covenant). <em>Bĕrît ʿôlām</em> is the highest designation for covenant permanence in the Hebrew Bible — it applies also to the Noahic covenant (Gen 9:16), the Sabbath (Exod 31:16), and the Davidic covenant (2 Sam 23:5). The use of "Jacob" and "Israel" as parallel names for the same person (both given by God — Gen 32:28; 35:10) suggests the totality of the patriarch\'s identity is included in the covenant.</p>',
    "11": '<p>"Saying, \'To you I will give the land of Canaan as your allotted inheritance (<em>ḥeḇel naḥălat-kem</em>)\'" — the land promise is the concrete content of the covenant. <em>Ḥeḇel</em> (measuring line, allotment) is the technical term for the apportioning of land by lot — each tribe received its <em>ḥeḇel</em> in the settlement (Josh 17:5, 14). <em>Naḥălāh</em> (inheritance, patrimony) emphasizes that the land is not conquered real estate but inherited family property given by divine grant. In Levitical law, inherited land could not be permanently sold (Lev 25:23-24) because "the land is mine; you are but aliens and strangers resident with me" — YHWH owns the land and Israel holds it as tenants.</p>',
    "12": '<p>"When they were but a few people in number, very few, and strangers (<em>gērîm</em>) in it" — the historical moment of the promise is emphasized: the covenant was made when Israel was numerically insignificant and legally without status (<em>gērîm</em> = resident aliens, without inheritance rights in the land). This is the theology of divine election against all odds: the promise was not made to a nation already established but to wandering strangers with no claim to the land. The covenant creates the nation, not the reverse. Deut 7:7-8 makes this explicit: "The LORD did not choose you because you were more numerous than other peoples... but because the LORD loves you."</p>',
    "13": '<p>"Wandering from nation to nation, from one kingdom to another people" — the patriarchal narrative in summary: Abraham moved from Ur to Haran to Canaan to Egypt; Isaac moved within Canaan among the Philistines; Jacob moved from Canaan to Paddan-Aram and back, then to Egypt. The wandering (<em>yithaʿlĕkû</em>) from nation to nation captures the rootlessness of the pre-settlement period. In the covenant\'s logic, this period of vulnerability serves to demonstrate that the patriarchs\' safety was entirely dependent on YHWH\'s protection, not on political power or territorial control.</p>',
    "14": '<p>"He allowed no one to oppress them; he rebuked kings on their account" — the specific incidents recalled: the rebuke of Pharaoh (Gen 12:17-20, where God afflicted Pharaoh\'s household after Abraham\'s deception about Sarah) and Abimelech of Gerar (Gen 20:3-7, where God appeared to Abimelech in a dream with a death warning: "You are as good as dead"). In both cases, the wandering aliens (with no legal protection) were protected by direct divine intervention against royal power. The verb "rebuked (<em>wĕyôkaḥ</em>)" suggests forensic correction — a formal, authoritative reprimand.</p>',
    "15": '<p>"\'Do not touch my anointed ones; do not harm my prophets\'" — the patriarchs are described with two exalted titles: <em>mĕšîḥāyw</em> (anointed ones) and <em>nĕbîʾāyw</em> (prophets). Neither term is applied to the patriarchs in Genesis itself — this is the Psalter\'s interpretive move. The "anointed" designation anticipates the priestly and royal anointing rituals; applied to the patriarchs it means they were consecrated to God\'s service. "Prophets" — Abraham is explicitly called a prophet in Gen 20:7 (the Abimelech narrative, just recalled in v. 14). The warning "do not touch" (<em>ʾal-tiggĕʿû</em>) is the strongest possible prohibition.</p>',
    "16": '<p>"He called down a famine on the land and broke every staff of bread (<em>maṭṭēh leḥem</em>)" — the Joseph narrative begins (vv. 16-22). "Broke every staff of bread" — <em>maṭṭēh leḥem</em> (staff of bread) is an idiom for the food supply as a support beam for life (cf. Lev 26:26; Ezek 4:16; 5:16; 14:13 — all use "breaking the staff of bread" as judgment). The famine is presented as YHWH\'s deliberate action ("he called down"), not a natural disaster — this frames the Joseph story theologically: YHWH orchestrated the famine to accomplish the covenant purpose of bringing Israel to Egypt and then delivering them from it.</p>',
    "17": '<p>"He sent a man before them — Joseph, sold as a slave" — the active subject is YHWH: "he sent (<em>šālaḥ</em>)." Joseph\'s being sold by his brothers (Gen 37:28) is reinterpreted as divine sending. The same language appears in Gen 45:5, 7, 8 where Joseph himself twice says "God sent me before you" and "God sent me ahead of you." The psalm draws on Joseph\'s own mature theological interpretation of his suffering. "A man before them" — a person positioned ahead in time to prepare the way, like a vanguard. The providential reversal — sold as a slave, becomes the deliverer — is the psalm\'s paradigm case of how YHWH works through human wickedness to fulfill covenant purposes.</p>',
    "18": '<p>"His feet were hurt with shackles; his neck was put in an iron collar (<em>barzĕl bāʾāh napšô</em>)" — the physical suffering of Joseph in Egyptian captivity. <em>Barzĕl bāʾāh napšô</em> is a grammatically difficult phrase: literally "iron entered into his soul/throat." Possible readings: (1) the iron collar pressed against his throat; (2) the iron shackles afflicted his whole being (<em>nepeš</em> as the seat of personal identity). The point is that the "sending" of v. 17 involved real physical suffering — the providential story should not be read as painless. Joseph endured years of physical hardship before the reversal.</p>',
    "19": '<p>"Until his prediction came true (<em>ʿad-ʿēt bōʾ-dĕbārô</em>) — the word of the LORD tested him (<em>ʾimrat YHWH ṣĕrāpātû</em>)" — "the word of the LORD tested him (<em>ṣārap</em>)" — <em>ṣārap</em> is the verb for smelting/refining metal to test its purity (Prov 17:3; Ps 12:6; 18:30). Joseph was "refined" by his suffering. "His prediction (<em>dĕbārô</em>)" — the dreams of Gen 37:5-11, which Joseph told his brothers and father. These dreams were the divine word that had to be tested through the years of slavery and imprisonment before they could be fulfilled. The verb "came true (<em>bōʾ</em>)" — literally "came," the same word used for the arrival of the prophetic word (cf. Isa 44:26; Ezek 33:33).</p>',
    "20": '<p>"The king sent and released him; the ruler of peoples set him free" — the passive form "sent" (<em>šālaḥ</em>) mirrors v. 17: just as YHWH "sent" Joseph to Egypt as a slave, Pharaoh "sent" to release him. The chiastic structure reinforces the providential irony. "Ruler of peoples (<em>mōšēl ʿammîm</em>)" — Pharaoh\'s universal title in the Egyptian world-view. The historical background: Joseph was released from prison because his God-given ability to interpret dreams was exactly what Pharaoh needed (Gen 41:14-16). The psalm compresses the narrative but preserves the theological point: Pharaoh\'s action was instrumentalized by YHWH\'s purpose.</p>',
    "21": '<p>"He made him lord of his household, and ruler over all his possessions" — Gen 41:41-44 records Pharaoh\'s appointment of Joseph: "I hereby put you in charge of the whole land of Egypt... without your word no one will lift hand or foot in all Egypt." The psalm summarizes this with the household/<em>bêt</em> vocabulary — Joseph administered Pharaoh\'s "house" (<em>bêtô</em>), which in Egyptian administrative parlance designated the royal household and its resources. The appointment echoes and reverses the beginning of the Joseph narrative: Potiphar put Joseph "in charge of his household" (Gen 39:4) — the same language, now scaled to national level.</p>',
    "22": '<p>"To instruct his officials as he saw fit and teach his elders wisdom" — Joseph\'s authority extended to education and governance: he could "bind (<em>le-ʾsōr</em>)" his officials according to his will and "teach wisdom (<em>yĕḥakkēm</em>)" to the elders. The wisdom dimension is significant: in the Egyptian context, wisdom (<em>ḥokmāh</em>) was both practical administration and cosmic insight. The ability to interpret dreams (Gen 40-41) was the demonstration of divine wisdom, and this same wisdom was now applied to governance. Joseph became an administrator who operated from divine insight — a model later applied to Solomon and, in Wisdom literature, to the sage who serves in royal courts.</p>',
    "23": '<p>"Then Israel came to Egypt; Jacob lived as an alien (<em>gār</em>) in the land of Ham" — the descent to Egypt, which the psalm has been building toward through the Joseph narrative (vv. 16-22), is summarized in a single verse. "Land of Ham" is the Psalter\'s poetic term for Egypt (cf. Ps 78:51; 106:22) — Ham as the father of Mizraim (Egypt) in Gen 10:6. "Israel" and "Jacob" used in parallel (as in v. 10) — the full national identity is present in the patriarch. The verb "lived as an alien (<em>gār</em>)" returns to the theme of v. 12 (the patriarchs as <em>gērîm</em>) — Israel\'s time in Egypt was an extended sojourn in alien status, fulfilling the prediction of Gen 15:13.</p>',
    "24": '<p>"The LORD made his people very fruitful; he made them too numerous for their foes" — the fulfillment of the Abrahamic blessing (Gen 12:2; 17:6; 22:17) happened in Egypt. The verb "made very fruitful (<em>wayyipreh</em>)" echoes Gen 1:28 (the creation mandate "be fruitful and multiply") and specifically Gen 47:27 ("Israel settled in Egypt... they acquired property there and were fruitful and increased greatly in number"). This is the paradox that creates the Exodus: YHWH\'s covenant-fulfilling blessing of population growth is precisely what triggers Egyptian hostility — "the Israelites were exceedingly fruitful... the land was filled with them" (Exod 1:7) causes Pharaoh\'s fear.</p>',
    "25": '<p>"Whose heart he turned to hate his people, to scheme against his servants" — this theologically loaded verse asserts that YHWH turned (<em>hāpak</em>) the Egyptian heart to hatred. This is the hardening tradition: as in Exod 4:21; 9:12; 10:1, 20, 27 (YHWH hardening Pharaoh\'s heart), the psalm places divine sovereignty behind the oppression. The theological problem this raises (why would YHWH incite hatred of his own people?) is resolved in the covenant logic: the oppression creates the conditions for the great deliverance that will demonstrate YHWH\'s power to Egypt and the world (Exod 9:16 — "I raised you up for this purpose, to show you my power and that my name might be proclaimed in all the earth").</p>',
    "26": '<p>"He sent Moses his servant, Aaron, whom he had chosen" — exactly as YHWH "sent" Joseph (v. 17), he now "sends" Moses. The parallel structure of the psalm is deliberate: each deliverance comes through a divine sending of a person. Moses is called "his servant" (<em>ʿabdô</em>) — the same title as Abraham in v. 6 and the highest honor designation. Aaron is "whom he had chosen (<em>bāḥar</em>)" — the election verb from v. 6. The doubling of Moses and Aaron reflects Exod 4:14-16 where YHWH designates Aaron as Moses\'s "mouth" and spokesman, addressing Moses\'s reluctance to speak. The sending structure of Ps 105 creates a pattern: YHWH solves each crisis through a chosen agent sent ahead.</p>',
    "27": '<p>"They performed his signs among them, his wonders (<em>môpĕtāyw</em>) in the land of Ham" — "signs and wonders" (<em>ʾôtôt ûmôpĕtîm</em>) is the technical phrase for the Exodus miracles (Deut 4:34; 6:22; 7:19; 26:8; 34:11; Ps 78:43). The signs (<em>ʾôtôt</em>) have a communicative function — they are signifiers that point to YHWH\'s power. The wonders (<em>môpĕtîm</em>) are the portents that cause awe and signal divine action. The "land of Ham" (Egypt) as the theater of these signs is significant: YHWH\'s power is demonstrated not in Israel\'s own territory but in the heart of the world\'s dominant empire.</p>',
    "28": '<p>"He sent darkness and made it dark; and they did not rebel against his words" — the plague order in Ps 105 differs from Exod 7-12 and Ps 78. Here the plagues begin with darkness (plague 9 in Exodus). The last half of the verse, "they did not rebel against his words," is grammatically ambiguous — does "they" refer to Moses and Aaron (who obeyed, unlike later), or to the Egyptians (who did not resist the darkness)? Most translations follow the former reading. The psalm is concerned with the plagues as demonstrations of divine word-power: each plague is the execution of YHWH\'s spoken command.</p>',
    "29": '<p>"He turned their waters into blood and caused their fish to die" — plague 1 (Exod 7:17-25). The Nile was the basis of Egyptian civilization — its annual inundation deposited the silt that made Egypt\'s agriculture possible. It was also sacred: the Nile was deified as Hapy, the god of inundation and fertility. Turning the Nile to blood was simultaneously a practical disaster (undrinkable water, dead fish as food source) and a theological judgment against the divine river. The fish dying was economically significant — fish was a major food source for Egypt (Num 11:5 — the Israelites remembered "the fish we ate in Egypt at no cost").</p>',
    "30": '<p>"Their land swarmed with frogs, even in the bedchambers of their kings" — plague 2 (Exod 8:1-15). The frog (<em>ṣĕpardēaʿ</em>) was associated with Heqet, the Egyptian frog-goddess of fertility who assisted in childbirth. The infestation of frogs in the most private royal spaces (bedchambers) was both a practical horror and a theological statement: YHWH\'s power penetrates to the most protected spaces. The phrase "in the bedchambers of their kings" emphasizes that Egyptian royal protection was no barrier against the divine plague. The Rev 16:13 image of three frog-like unclean spirits from the dragon, beast, and false prophet echoes this plague imagery.</p>',
    "31": '<p>"He spoke, and swarms of flies came, and gnats throughout their country" — plagues 3 (<em>kinnîm</em>, gnats/lice, Exod 8:16-19) and 4 (<em>ʿārōb</em>, swarms/flies, Exod 8:20-32) are combined in a single verse. The gnats were significant because the Egyptian magicians could not replicate them and said "This is the finger of God" (Exod 8:19) — the first acknowledged defeat of the Egyptian court magicians. The swarms of flies were the first plague that specifically excluded Goshen (where Israel lived), demonstrating YHWH\'s selective application of judgment.</p>',
    "32": '<p>"He gave them hail for rain, and lightning throughout their land" — plague 7 (Exod 9:13-35, hail). Exod 9:23-24 describes it as the most severe hailstorm "in all the land of Egypt since it had become a nation." The plague was accompanied by fire (lightning) running along the ground — combining the natural disaster of hail with the supernatural element of fire. The hail destroyed the crops that were in growth — flax and barley (Exod 9:31-32) but not wheat (which came later, explaining why Pharaoh relented and then hardened again). The psalm connects hail and lightning as manifestations of YHWH\'s storm-warrior theophany.</p>',
    "33": '<p>"He struck down their vines and their fig trees and shattered the trees of their country" — still the hail plague (Exod 9:25: "it beat down every plant in the field and stripped every tree"). Vines and fig trees as paradigmatic food sources — their destruction represents total agricultural devastation. In Israel\'s covenant theology, sitting "under your vine and fig tree" (1 Kgs 4:25; Mic 4:4; Zech 3:10) was the image of covenant prosperity and peace. The destruction of vine and fig tree was the inversion of this blessing — the covenant curse applied to Egypt.</p>',
    "34": '<p>"He spoke, and locusts came, and young locusts without number (<em>wĕyeleq wĕʾên mispār</em>)" — plague 8 (Exod 10:1-20, locusts). "He spoke" (<em>ʾāmar</em>) — the plague comes through divine speech-command, reinforcing the word-power theology of the psalm. The young locusts (<em>yeleq</em> — a specific stage of locust development, also translated "cricket" or "locust nymph") in addition to the adult locusts (<em>ʾarbeh</em>) emphasize the completeness of the infestation. Exod 10:14 describes the locust swarm as unprecedented: "never before had there been such a locust plague on Egypt, nor would there ever be again." Joel 1-2 would later use locust imagery for eschatological judgment.</p>',
    "35": '<p>"They devoured all the vegetation in their land and ate up the fruit of their ground" — the locust plague completed what the hail had left: all crops and vegetation were consumed. Exod 10:15 says the locusts "covered all the ground until it was black. They devoured all that was left after the hail — everything growing in the fields and the fruit on the trees. Nothing green remained on tree or plant in all the land of Egypt." The total stripping of Egypt\'s agricultural base represents the inversion of the land\'s natural fertility — the Egypt that was "like the garden of the LORD, like the land of Egypt" (Gen 13:10) became desolate.</p>',
    "36": '<p>"He also struck down all the firstborn in their land, the firstfruits of all their manhood" — plague 10 (Exod 12:29-30). "Firstborn" (<em>bĕkôr</em>) and "firstfruits of all their manhood (<em>rēʾšît kol-ʾônām</em>)" are parallel terms — the firstborn as the firstfruits of human reproductive strength. In ANE culture, the firstborn son carried the family name, inheritance, and honor. The simultaneous death of every Egyptian firstborn from the royal house to the prisoner was a social catastrophe beyond any of the preceding plagues. Exod 4:22-23 had established the theological logic: "Israel is my firstborn son... let my son go... or I will kill your firstborn son."</p>',
    "37": '<p>"He led Israel out with silver and gold, and not one among his tribes stumbled" — Exod 12:35-36: the Israelites asked the Egyptians for silver and gold objects, and "the LORD had made the Egyptians favorably disposed toward the people, and they gave them what they asked for; so they plundered the Egyptians." The psalm describes this as Israel going out "laden with silver and gold" — the plundering of the oppressors as a form of back-payment for centuries of slave labor. "Not one stumbled (<em>wĕʾên bôkēš bišbāṭāyw</em>)" — the entire nation, after generations of slavery, departed in an organized, healthy procession. The YHWH who promised to bring them out "with great wealth" (Gen 15:14) fulfilled his word.</p>',
    "38": '<p>"Egypt was glad when they left, for the dread of Israel had fallen on them" — Exod 12:33 records that "the Egyptians urged the people to hurry and leave the country." After ten plagues, Egypt wanted to be rid of Israel. The "dread (<em>paḥad</em>)" of Israel is the covenantal terror that YHWH promised to send ahead of his people (Exod 23:27-28; Deut 2:25; 11:25). In the military context, this is the divine-warrior tradition: YHWH goes before his people and causes their enemies\' hearts to melt (Josh 2:9-11 — Rahab reports that "a great fear of you has fallen on us").</p>',
    "39": '<p>"He spread a cloud for covering, and fire to give light at night" — the wilderness provision (vv. 39-41). The pillar of cloud and fire (Exod 13:21-22; 14:19-24) served multiple functions: guidance (leading), protection (covering from the desert sun and protecting the rear at the sea crossing), and communication (the divine presence appearing in the cloud, Exod 33:9-10; Num 12:5). The cloud as "covering (<em>sēk</em>)" suggests a protective canopy — shielding Israel from the Sinai sun. In Second Temple interpretation, the cloud became associated with the <em>Šĕkînāh</em>, the divine dwelling presence.</p>',
    "40": '<p>"They asked, and he brought quail, and satisfied them with bread from heaven (<em>leḥem šāmayim</em>)" — the quail and manna (Exod 16; Num 11). The "asking" in the psalm is the Israelites\' petition for food — in Numbers 11, this asking is laden with ingratitude and complaint ("who will give us meat to eat?"). The psalm\' summarizes the provision without the complaint — a different rhetorical emphasis than Ps 78 (which will dwell on the sin) or Ps 106 (which will recall the rebellion). "Bread from heaven (<em>leḥem šāmayim</em>)" — the phrase Jesus picks up in John 6:31-35, where he identifies himself as the true bread from heaven that the manna only anticipated.</p>',
    "41": '<p>"He opened the rock, and water gushed out; it flowed like a river through the desert" — the water from the rock (Exod 17:1-7 at Horeb/Meribah; Num 20:1-13 at Meribah-Kadesh). "It flowed like a river (<em>nāhār</em>) through the desert" — an abundant, flowing river in the arid Sinai wilderness. Paul reads this providential provision christologically in 1 Cor 10:4: "they drank from the spiritual rock that accompanied them, and that rock was Christ." The rock that produces water in the wilderness becomes a type: divine provision through an unexpected source.</p>',
    "42": '<p>"For he remembered his holy promise to Abraham his servant" — the summarizing theological principle of the entire historical survey. Everything recounted in vv. 7-41 (the patriarchal protection, the Joseph providential reversal, the Exodus plagues, the wilderness provision) had a single divine motivation: YHWH remembered (<em>zākar</em>) his promise (<em>dĕbar-qāḏšô</em>, his holy word) to Abraham. The covenant promise of Gen 12:1-3; 15; 17; 22:15-18 was the engine driving every subsequent divine act. "Abraham his servant" — the title repeats from v. 6 and vv. 26, 42 form a bracket: the psalm opened by addressing "seed of Abraham, his servant" (v. 6) and now closes by naming the patriarch himself.</p>',
    "43": '<p>"He led out his people with rejoicing, his chosen ones with shouts of joy" — the Exodus is experienced as festive celebration (<em>bĕśāśôn</em> = with joy, exultation; <em>bĕrinnāh</em> = with shouts/singing). This matches the Song of Moses (Exod 15:1-21) — the Exodus was received with singing and dancing at the sea. The "chosen ones (<em>bĕḥîrāyw</em>)" return to the election theme of v. 6 — the people who began the psalm as the "chosen" of God have now been rescued in fulfillment of the covenant. The Exodus as joyful procession contrasts with Ps 106\'s account of the same events, where the dominant tone is failure and judgment.</p>',
    "44": '<p>"He gave them the lands of the nations; they took possession of what other peoples had worked for" — the gift of the land (Josh 11-21). Deut 6:10-11 anticipates this: "The LORD your God will bring you into the land... large, flourishing cities you did not build, houses filled with all kinds of good things you did not provide, wells you did not dig, vineyards and olive groves you did not plant." The psalm echoes this Deuteronomic theology of the land as inheritance, not conquest achievement. The nations\' cities, fields, and vineyards were given by YHWH for Israel to inhabit — a radical gift economy that emphasized divine generosity.</p>',
    "45": '<p>"So that they might keep his precepts (<em>ḥuqqāyw</em>) and observe his laws (<em>tôrōtāyw</em>). Praise the LORD (<em>hallĕlû-yāh</em>)!" — the purpose clause that closes the entire historical survey. The entire sequence — covenant, patriarchs, Joseph, plagues, Exodus, wilderness, land — was aimed at this: Israel keeping Torah. The gift of the land was not an end in itself but the means of covenant life, the space in which obedience to YHWH\'s precepts was possible. The Deuteronomic logic: "Do this and live" (Deut 30:15-20). The closing <em>Hallĕlû-yāh</em> mirrors the opening call of v. 1 and will open Ps 106 — the linked pair of psalms frames both grace and law within the praise of the covenant God.</p>'
  },
  "106": {
    "1": '<p>Psalm 106 opens with the same <em>Hallĕlû-yāh</em> that closed Ps 105, binding the two psalms into a deliberate diptych. The matched structure: Ps 105 surveys YHWH\'s gracious acts in history; Ps 106 surveys Israel\'s repeated failures within that same history. Both use the same historical tradition (Exodus through the settlement period) but with opposite emphases. Ps 106 is a national confession of sin in the form of a historical survey — a genre similar to Neh 9:5-37 and Dan 9:4-19, which also recall the pattern of sin-and-grace through Israel\'s history. "His steadfast love (<em>ḥesed</em>) endures forever" — the liturgical response formula from Ps 118 and 136, placed here in the opening call to praise before the catalogue of failures. The confession can only be made because the answer is already known: <em>ḥesed</em> endures.</p>',
    "2": '<p>"Who can proclaim the mighty acts (<em>gĕbûrôt</em>) of the LORD or fully declare his praise?" — the rhetorical question acknowledges the inadequacy of any recitation to capture the fullness of divine acts. <em>Gĕbûrôt</em> (mighty deeds, heroic acts) is the vocabulary of divine warfare and power (cf. Ps 145:4; 150:2; Job 26:14). The question is not a denial that praise is possible but a confession that it is always incomplete. In the context of a psalm that will catalog Israel\'s failures, this opening acknowledgment of YHWH\'s incomprehensible power creates the contrast: Israel\'s faithlessness is set against a background of inexhaustible divine greatness that even praise cannot fully encompass.</p>',
    "3": '<p>"Blessed are those who act justly (<em>šōmĕrê mišpāṭ</em>), who always do what is right (<em>ʿōśēh ṣĕdāqāh bĕkol-ʿēt</em>)" — a wisdom beatitude (<em>ʾašrê</em>) placed at the opening of a confession psalm. The beatitude defines what the confessors should have been — the standard against which the failures of vv. 6-46 are measured. "Always do what is right" (<em>bĕkol-ʿēt</em> = in every time/season) sets an absolute consistency that the historical survey will show Israel consistently failed to maintain. The function of the beatitude here is to set the standard before the confession begins — making the depth of the failure clear by contrast.</p>',
    "4": '<p>"Remember me, O LORD, when you show favor to your people; come to my aid when you save them" — the first-person petition embedded in a communal psalm signals that this is not merely historical recitation but personal intercession. The individual speaker identifies with the community of Israel in both its past failures and its future hope of restoration. "When you show favor (<em>birṣôn</em>)" — <em>rāṣôn</em> (favor, acceptance, delight) is the covenantal term for the moment of divine acceptance, used of acceptable sacrifices (Lev 1:3) and of the year of YHWH\'s favor (Isa 61:2, which Jesus reads in Luke 4:19). The prayer is that the individual be included in the community\'s restoration.</p>',
    "5": '<p>"That I may enjoy the prosperity of your chosen ones, that I may share in the joy of your nation, and join your inheritance in giving praise" — three desired participations: the prosperity (<em>ṭôbāh</em>) of the chosen, the joy (<em>śimḥāh</em>) of the nation, the praise of the inheritance (<em>naḥălāh</em>). The "inheritance" here refers both to the land and to the covenantal identity of the people — the whole complex of relationship, land, and worship that constitutes Israel\'s life before YHWH. The prayer orients toward the future restoration that the psalm will build toward — after the confession of past failure comes the hope of future inclusion in the covenant community\'s restoration.</p>',
    "6": '<p>"We have sinned, even as our ancestors did; we have done wrong and acted wickedly" — the confession proper begins (vv. 6-46). The phrase "even as our ancestors did (<em>kĕʾăbôtênû</em>)" is the key move: the present generation identifies with past generations\' sins. This is the solidarity-in-sin that characterizes the great OT confessions (Neh 9:16-18; Dan 9:4-8; Ezra 9:6-7). The three-verb climax — "sinned (<em>ḥāṭāʾnû</em>), done wrong (<em>heʿăwînû</em>), acted wickedly (<em>hiršaʿnû</em>)" — covers the three categories of transgression in Hebrew moral theology: missing the mark, bending/distorting, and acting wickedly/criminally. The full range of moral failure is owned without qualification.</p>',
    "7": '<p>"When our ancestors were in Egypt, they did not grasp the meaning of your wonders; they did not remember your many acts of faithful love, and they rebelled by the sea, the Red Sea" — the first failure: failure to understand the plagues and Exodus. "Did not grasp (<em>lōʾ hiskîlû</em>)" — the verb is the wisdom term for discernment and understanding (Prov 1:3; Dan 1:4). The plagues were signs with interpretive content, but the people did not understand their theological significance. The rebellion at the sea (Exod 14:10-12 — the people said "Was it because there were no graves in Egypt that you brought us to the desert to die?") is the paradigmatic failure of faith at the very moment of greatest divine action.</p>',
    "8": '<p>"Yet he saved them for his name\'s sake, to make his mighty power known" — the divine motivation for rescue despite failure: "for his name\'s sake (<em>lĕmaʿan šĕmô</em>)." The "name" (<em>šēm</em>) in covenantal theology is YHWH\'s reputation and self-disclosure — his name is at stake when his covenant people are at risk. Ezekiel develops this most explicitly (Ezek 20:9, 14, 22; 36:21-23): YHWH repeatedly says he acted "for the sake of my name, so that it would not be profaned in the sight of the nations." The salvation serves the purpose of demonstrating divine power and character — even the failure of the people cannot stop YHWH from fulfilling his name\'s commitments.</p>',
    "9": '<p>"He rebuked the Red Sea, and it dried up; he led them through the depths as through a desert" — the sea crossing described as a divine rebuke (<em>wayyigeʿar</em>). YHWH "rebukes" the sea as a superior authority commands an inferior — the same verb used for rebuking demonic forces in the NT (Matt 8:26; 17:18; Mark 1:25). The drying up of the sea (<em>wĕyeḥĕrab</em>) echoes Gen 1 (separation of waters from dry land) and Exod 14:21 (the east wind drying the sea floor). "Through the depths (<em>tĕhômôt</em>) as through a desert" — the cosmic deep water (Gen 1:2 <em>tĕhôm</em>) becomes as passable as dry land. The crossing reversed the chaos-order dynamic: what was impassable becomes passage.</p>',
    "10": '<p>"He saved them from the hand of the foe; he redeemed them from the hand of the enemy" — the military rescue language. "Redeemed (<em>gāʾal</em>)" — the kinsman-redeemer verb (also used in Ps 69:18; Isa 43:1; 44:6) applied to the corporate rescue of Israel from Egypt. Exod 15:13 uses the same verb ("in your unfailing love you will lead the people you have redeemed"). The sea crossing was not only miraculous escape but covenantal ransom — YHWH acted as Israel\'s <em>gōʾēl</em>, the close kinsman who buys back the enslaved family member. The "foe" (<em>ʾōyēb</em>) and "enemy (<em>śônēʾ</em>)" in parallel refer to the Egyptian army pursuing in chariots.</p>',
    "11": '<p>"The waters covered their adversaries; not one of them survived" — Exod 14:28: "Not one of them survived." The totality of Egyptian military destruction at the sea is emphasized. The covering of the waters returns to the creation imagery of Gen 1:2 (<em>tĕhôm</em> covering the deep) — the cosmic waters that YHWH held back for Israel\'s crossing now return to cover the Egyptians. The irony: the people who threw Israelite infants into the Nile (Exod 1:22) are themselves swallowed by water. Ps 78:53 draws the same connection. The complete annihilation of the pursuing army left Egypt militarily defenseless — a point emphasized in the Song of Moses.</p>',
    "12": '<p>"Then they believed his promises and sang his praise" — the brief moment of faith following the sea crossing. Exod 14:31: "When the Israelites saw the mighty hand of the LORD displayed against the Egyptians, the people feared the LORD and put their trust in him and in Moses his servant." The Song of Moses immediately follows (Exod 15:1-21). The psalm places this as a single verse between the great deliverance (vv. 9-11) and the immediate onset of failure (vv. 13-14) — the brevity is pointed: the faith lasted a very short time. The structure of the whole psalm is this pattern repeated: rescue, brief response, rapid return to failure.</p>',
    "13": '<p>"But they soon forgot what he had done and did not wait for his plan (<em>ʿēṣāh</em>) to unfold" — the transition word "but" (<em>mĕhārû šāḵĕḥû</em> = "they quickly forgot") marks the collapse of the faith of v. 12. In Exod 15:22-17:7, the sequence from the sea crossing to the wilderness complaints is remarkably rapid — within days the people were complaining about water, food, and leadership. "Did not wait for his plan (<em>ʿēṣāh</em>)" — <em>ʿēṣāh</em> (counsel, plan, purpose) is the Wisdom vocabulary for the divine strategy operating through history (Prov 19:21; Isa 14:26-27; 46:10-11). They would not trust a plan they could not see.</p>',
    "14": '<p>"In the wilderness they gave in to their craving; in the wasteland they tested God (<em>waynassû-ʾēl bîšîmôn</em>)" — Num 11: the "lusting" (<em>wĕyitʾawwû taʾăwāh</em> — intense craving) for meat. The Israelites remembered the "free" fish, cucumbers, melons, leeks, onions, and garlic of Egypt (Num 11:5) and rejected the manna YHWH provided. "Tested God (<em>nāsāh</em>)" in the wilderness — the same verb as the Meribah place-name (Exod 17:7 — Massah means "testing"). To test YHWH is to demand that he prove himself on their terms — the inversion of the proper relationship (YHWH tests people, not the reverse: Gen 22:1; Deut 8:2).</p>',
    "15": '<p>"He gave them what they asked for, but sent a wasting disease among them" — Num 11:31-34: YHWH sent a wind that brought quail into the camp, but while the people were still eating, "the anger of the LORD burned against the people, and he struck them with a severe plague." The place was named Kibroth-hattaavah (Graves of Craving). The principle: God sometimes grants requests that are themselves a judgment — receiving what you demand when what you demand is against your good. Paul applies this pattern in 1 Cor 10:5-6: the wilderness events are recorded as "examples (<em>tupoi</em>) to keep us from setting our hearts on evil things as they did."</p>',
    "16": '<p>"In the camp they grew envious of Moses and of Aaron, the holy one of the LORD" — the Korah rebellion (Num 16). "Grew envious (<em>wayyĕqannĕʾû</em>)" — the same root as the "jealousy" / "zeal" vocabulary. Korah and his followers challenged Moses\'s and Aaron\'s authority: "The whole community is holy, every one of them, and the LORD is with them. Why then do you set yourselves above the LORD\'s assembly?" (Num 16:3). "Aaron, the holy one of the LORD (<em>qĕdôš YHWH</em>)" — this title appears elsewhere only in Ps 16:10 (the "Holy One" whom God will not abandon to the grave) and is applied to Jesus in Mark 1:24. The priestly function is what is being challenged.</p>',
    "17": '<p>"The earth opened up and swallowed Dathan; it buried the company of Abiram" — Num 16:31-33: "the ground under them split apart and the earth opened its mouth and swallowed them and their households." Notably, the psalm names Dathan and Abiram (the Reubenite co-conspirators, Num 16:1) rather than Korah (the Levite who initiated the rebellion). Num 26:11 notes that "the sons of Korah, however, did not die" — Korah\'s line survived, and the sons of Korah later became a prominent musical guild associated with the Psalter (Pss 42-49; 84-85; 87-88). The selective naming may reflect sensitivity about this Korahite heritage.</p>',
    "18": '<p>"Fire blazed among their followers; a flame consumed the wicked" — Num 16:35: "And fire came out from the LORD and consumed the 250 men who were offering the incense." The 250 men who offered unauthorized incense were consumed by divine fire — the same judgment that fell on Nadab and Abihu (Lev 10:1-2) for offering "unauthorized fire" before YHWH. The bronze censers of the 250 were hammered into an overlay for the altar as a warning (Num 16:36-40). The twin judgments — earth swallowing (Korah, Dathan, Abiram) and fire consuming (the 250) — demonstrate YHWH\'s absolute authority over priestly access and appointment.</p>',
    "19": '<p>"At Horeb they made a calf and worshiped an idol of cast metal" — the golden calf (Exod 32). "Horeb" is Deuteronomy\'s name for Sinai — the psalm uses the northern/Deuteronomic terminology. The making of the calf while Moses was receiving the Torah on the mountain is the paradigmatic apostasy in the Hebrew Bible. The calf (<em>ʿēgel</em>) was likely a pedestal for the invisible YHWH (as the cherubim were in the tabernacle), but the prohibition of images was violated regardless of intent. Aaron\'s declaration "These are your gods, Israel, who brought you up out of Egypt" (Exod 32:4) transferred the Exodus attribution from YHWH to the created object.</p>',
    "20": '<p>"They exchanged their glory (<em>kĕbôdām</em>) for an image of a bull that eats grass" — a devastating juxtaposition: the <em>kābôd</em> (glory, the presence of YHWH himself, the pillar of fire and cloud) for a grass-eating ox. Paul quotes this verse in Rom 1:23 as the paradigmatic act of human idolatry: "they exchanged the glory of the immortal God for images made to look like a mortal human being and birds and animals and reptiles." The exchange motif (give up X for Y) is Paul\'s diagnostic of universal religious failure — the same exchange that Israel made at Horeb is the structure of all idolatry. The bull eats grass — its nature is utterly mundane, incapable of the glory it supposedly represents.</p>',
    "21": '<p>"They forgot God their Savior (<em>ʾēl môšîʿām</em>), who had done great things in Egypt" — the golden calf episode is characterized as forgetting. <em>Šākaḥ</em> (forget) is the covenant anti-virtue, the opposite of <em>zākar</em> (remember) which Ps 105 repeatedly praised YHWH for doing. Deut 6:12; 8:14, 19 warn Israel three times "be careful that you do not forget the LORD your God." The saving acts in Egypt were so recent and so dramatic that the forgetting is presented as culpable — a willful suppression of evidence rather than a lapse of memory.</p>',
    "22": '<p>"Miracles in the land of Ham and awesome deeds by the Red Sea" — "land of Ham" (Egypt) as in Ps 78:51; 105:23, 27. The "awesome deeds (<em>nôrāʾôt</em>)" by the Red Sea refer to both the sea crossing (Ps 106:9-11) and the destruction of the Egyptians (Exod 15:11: "Who among the gods is like you, LORD? Who is like you — majestic in holiness, awesome in glory, working wonders?"). The psalm lists the greatest demonstrations of divine power precisely at the point of greatest human ingratitude: the golden calf was made immediately after these events.</p>',
    "23": '<p>"So he said he would destroy them — had not Moses, his chosen one, stood in the breach before him to keep his wrath from destroying them" — Exod 32:10-14: YHWH said "Now leave me alone so that my anger may burn against them and that I may destroy them" — and Moses interceded. "Stood in the breach (<em>ʿāmaḏ bappeṣ</em>)" — military imagery: standing in the gap in a wall to prevent enemy entry (cf. Ezek 22:30 — "I looked for someone among them who would build up the wall and stand before me in the gap on behalf of the land so I would not have to destroy it, but I found no one"). Moses\'s intercession is a type of mediation that prevents divine judgment — anticipating Christ\'s intercessory role.</p>',
    "24": '<p>"Then they despised the pleasant land (<em>ʾereṣ ḥemdāh</em>); they did not believe his promise" — the Kadesh-Barnea failure (Num 13-14). "Pleasant land (<em>ʾereṣ ḥemdāh</em>)" — the term suggests something desired, precious, delightful (Jer 3:19; Zech 7:14 use the same phrase for the promised land). The people "despised" (<em>wayyimʾăsû</em> = rejected, scorned) the very thing YHWH promised — the failure to believe the spies\' minority report (Caleb and Joshua) and the consequent refusal to enter. Heb 3:7-4:11 reads this episode as a warning to the church not to harden hearts as Israel did, so as not to fail to enter God\'s "rest."</p>',
    "25": '<p>"They grumbled in their tents and did not obey the LORD" — Num 14:1-4: the people wept aloud, grumbled against Moses and Aaron, and said "We should choose a leader and go back to Egypt." "Grumbled in their tents (<em>wayyĕrāgĕnû bĕʾohŏlêhem</em>)" — the image of private complaint circulating through the camp. The tent setting (private space) contrasts with the public announcement of YHWH\'s command — the refusal was whispered and spread before it became overt. Deut 1:27 recalls the same event: "You grumbled in your tents and said, \'The LORD hates us; so he brought us out of Egypt to deliver us into the hands of the Amorites to destroy us.\'"</p>',
    "26": '<p>"So he swore to them with uplifted hand that he would make them fall in the wilderness" — the oath of judgment. In Num 14:28-35, YHWH swears (<em>ḥay-ʾānî</em> = as I live) that the generation that refused to enter will die in the wilderness over forty years — one year for each day of the spies\' reconnaissance. "With uplifted hand" (<em>wayyiśśāʾ yāḏô</em>) — the standard gesture for oath-taking in the ANE, representing invocation of heaven as witness. Ezek 20:15, 23 also uses this gesture for divine oaths of judgment. The oath of blessing (v. 9 — sworn to Abraham) is now matched by an oath of judgment — both are equally irrevocable.</p>',
    "27": '<p>"...and make their descendants fall among the nations and scatter them throughout the lands" — the horizon of the oath extends beyond the wilderness generation to the exile. Lev 26:33-38; Deut 4:27; 28:64-68 all predict the scattering among the nations as the ultimate covenant curse for persistent unfaithfulness. The psalm, likely composed in or after the exile, reads the wilderness oath as having long-range consequences: the pattern of disobedience that began in the wilderness ultimately resulted in the destruction of Jerusalem and exile to Babylon. The psalm thus reads Israel\'s whole history as a single continuous pattern.</p>',
    "28": '<p>"They yoked themselves to the Baal of Peor and ate sacrifices offered to lifeless gods (<em>zibḥê mētîm</em>)" — the Baal of Peor episode (Num 25:1-9). Israel at Shittim joined in the Moabite sacred prostitution and sacrificial meals associated with Baal of Peor. "Yoked (<em>wayyiṣṣāmĕdû</em>)" — the image of being harnessed to, as animals are yoked to a plow: they attached themselves to the Baal. "Sacrifices offered to lifeless gods (<em>mētîm</em>)" — <em>mētîm</em> = the dead. The baals as dead things is the prophetic polemic against idols (cf. Ps 115:4-8; Isa 44:9-20; Jer 10:3-10). Paul quotes the Peor tradition in 1 Cor 10:8 as a warning: "We should not commit sexual immorality, as some of them did."</p>',
    "29": '<p>"They aroused the LORD\'s anger by their wicked deeds, and a plague broke out among them" — Num 25:3: "the LORD\'s anger burned against them" and 25:8-9: "the plague against the Israelites was stopped... but those who died in the plague numbered 24,000." The "plague" here is the divine response to covenant violation — the same mechanism as the plagues against Egypt, now turned inward against YHWH\'s own people. The covenant curses of Lev 26:25 and Deut 28:21-22 include pestilence as a consequence of idolatry. This episode demonstrates that the covenant\'s sanctions applied equally to Israel itself, not only to its enemies.</p>',
    "30": '<p>"But Phinehas stood up and intervened (<em>wayyĕpalēl</em>), and the plague was checked (<em>wayyēʿăṣar hammaggēpāh</em>)" — Num 25:7-8: Phinehas, grandson of Aaron, saw an Israelite man take a Midianite woman into his tent in full view of the congregation (while the people were weeping at the entrance to the tent of meeting), and drove a spear through both of them. "Intervened (<em>pālaʾ</em>)" — the verb means to pray/intercede (so most translations) or possibly to execute judgment. Either way, the act stopped the plague. This act of zealous intercession/judgment became paradigmatic in later tradition: 1 Macc 2:26 (Mattathias invokes Phinehas as the model for his killing of a Jew who approached a pagan altar); Sir 45:23-24 (Phinehas praised for making atonement for Israel).</p>',
    "31": '<p>"This was credited to him as righteousness for endless generations to come" — Num 25:12-13: YHWH gave Phinehas "my covenant of peace... a covenant of a lasting priesthood" because he was zealous for his God and made atonement for the Israelites. "Credited to him as righteousness (<em>wattēḥāšeb lô lĕṣĕḏāqāh</em>)" — the identical grammatical construction as Gen 15:6: "Abram believed God, and it was credited to him as righteousness." The parallel is deliberate: Abraham\'s faith and Phinehas\'s action are structurally equivalent in covenant-accounting — both are credited (<em>ḥāšab</em>) as righteousness by divine reckoning. Paul\'s argument in Rom 4 about Abraham\'s faith is thus part of a larger covenant-accounting tradition.</p>',
    "32": '<p>"By the waters of Meribah they angered the LORD, and trouble came to Moses because of them" — the waters of Meribah-Kadesh (Num 20:1-13, which is distinct from the earlier Meribah at Horeb in Exod 17). At Meribah-Kadesh, Moses and Aaron struck the rock twice instead of speaking to it as commanded, and YHWH said "Because you did not trust in me enough to honor me as holy in the sight of the Israelites, you will not bring this community into the land I give them" (Num 20:12). "Trouble came to Moses because of them (<em>wayyēraaʿ lĕmōšeh biglĕlām</em>)" — Moses suffered the consequences for his sin, but the people bore responsibility for provoking the situation by their rebellion.</p>',
    "33": '<p>"For they rebelled against the Spirit of God (<em>ʾet-rûḥô</em>), and rash words came from Moses\' lips" — the causal chain: the people\'s rebellion provoked Moses to speak rashly. "They rebelled against his Spirit (<em>mārû ʾet-rûḥô</em>)" — Isa 63:10 uses the same vocabulary: "they rebelled and grieved his Holy Spirit." The Spirit of YHWH is grieved/rebelled against by Israel\'s persistent disobedience — a statement that anticipates Paul\'s warning in Eph 4:30 ("do not grieve the Holy Spirit of God"). Moses\' rash words (<em>bāṭāʾ biśpātāyw</em> = spoke rashly with his lips) may refer to the angry address "Listen, you rebels" (Num 20:10) or to striking the rock as an act of angry deviation.</p>',
    "34": '<p>"They did not destroy the peoples as the LORD had commanded them" — the failure to drive out the Canaanites (Num 33:55; Judg 1:19-2:5). YHWH\'s command was explicit: drive out the inhabitants and destroy their religious sites (Exod 34:11-16; Deut 7:1-5; 20:16-18). The reason given in the Torah texts is twofold: (1) the land must be ritually clean for YHWH\'s dwelling; (2) the Canaanites will ensnare Israel into idolatry if left. The actual situation in Judges shows the prophetic accuracy of this warning — the incomplete conquest immediately produced the syncretism the Torah warned against.</p>',
    "35": '<p>"But they mingled with the nations and adopted their customs (<em>wayyilmĕdû maʿăśêhem</em>)" — the Judges pattern described in summary. "Mingled (<em>wayyitʿārbû</em>)" — intermarried and socially integrated with Canaanites. "Adopted their customs (<em>maʿăśêhem</em>)" — learned and followed their practices. Deut 18:9 had warned "do not learn (<em>lōʾ tilmad</em>) to imitate the detestable ways of the nations." The covenant command "do not learn" is inverted in the psalm: "they learned (<em>wayyilmĕdû</em>)." The same word, the same command, the exact opposite outcome. This learning was the mechanism of assimilation — not forced but voluntary absorption into surrounding culture.</p>',
    "36": '<p>"They worshiped their idols, which became a snare (<em>mōqēš</em>) to them" — the Deuteronomic prediction fulfilled. Deut 7:16: "do not serve their gods, for that will be a snare (<em>mōqēš</em>) to you." The same word, the exact same outcome. The "snare" imagery: idolatry presents itself as attractive (hence the word "snare" — a trap that looks safe until it closes). Once Israel was ensnared in Canaanite worship, the difficulty of extraction was enormous — as the entire Judges-Kings narrative demonstrates.</p>',
    "37": '<p>"They sacrificed their sons and their daughters to false gods (<em>laššēḏîm</em>)" — the Molech worship and child sacrifice (Lev 18:21; 20:2-5; 2 Kgs 23:10; Jer 32:35). <em>Šēḏîm</em> (demons, false gods) — the term appears only here and in Deut 32:17 in this sense. The sacrifice of children is presented as the ultimate covenant violation — the complete inversion of the covenant promise of children as YHWH\'s gift (Ps 127:3). Archaeological evidence for child sacrifice (<em>molk</em> offerings) in the Levant is debated but some evidence exists at Carthage (which colonized from Canaan) and in ancient Near Eastern texts.</p>',
    "38": '<p>"They shed innocent blood, the blood of their sons and daughters, whom they sacrificed to the idols of Canaan, and the land was desecrated by their blood" — the covenant-legal framing: bloodshed defiles the land (Gen 4:10-12; Num 35:33-34: "Do not pollute the land where you are... bloodshed pollutes the land, and atonement cannot be made for the land on which blood has been shed"). The blood of sacrificed children "cried out" from the ground (the Cain and Abel principle — Gen 4:10), and the land became ritually impure (<em>ṭāmēʾ</em> = defiled) through the accumulated bloodshed. The defilement of the land by innocent blood was one of the reasons given for YHWH\'s ejection of Israel from it (Ezek 22:1-16).</p>',
    "39": '<p>"They defiled themselves by what they did; by their deeds they prostituted themselves (<em>wayyiznû bĕmaʿallêhem</em>)" — "prostituted themselves" (<em>zānāh</em>) is the standard prophetic metaphor for idolatry as marital unfaithfulness (Hos 1-3; Jer 3:1-9; Ezek 16; 23). Israel\'s covenant with YHWH was understood as a marriage — idolatry was adultery-and-prostitution. The metaphor was not merely rhetorical: the Baal cult explicitly involved sacred prostitution in some forms. The "defilement (<em>ṭāmēʾ</em>)" language links v. 39 with v. 38 — the same root for ritual impurity — connecting bloodshed and sexual apostasy as mutually reinforcing covenant violations.</p>',
    "40": '<p>"Therefore the LORD\'s anger burned against his people and he abhorred his inheritance" — the judicial conclusion to the catalogue of failures (vv. 6-39). "Abhorred his inheritance (<em>wĕyĕtaʿēb ʾet-naḥălātô</em>)" — the language is startling: YHWH used the "abhor" word (<em>tāʿab</em>) that he applied to the Canaanite detestable practices (Lev 18:30; Deut 18:9-12) — now applied to Israel itself. The people who were told to avoid the abominations of the nations became abominable themselves. The covenant symmetry: the very language of covenant protection ("inheritance") is now paired with "abhorred."</p>',
    "41": '<p>"He gave them into the hands of the nations, and their enemies ruled over them" — the Judges cycle articulated in a single verse. The pattern of Judg 2:11-23 is exactly this: Israel abandons YHWH, YHWH "gives them into the hands of raiders," enemies rule, Israel cries out. "He gave them into the hands" (<em>wayyittnēm bĕyad-gôyim</em>) — the giving language is judicial: YHWH is the sovereign who decides the outcome of battles by handing over (or withholding) a nation. Israel\'s military defeats are interpreted theologically as YHWH\'s active decision to withdraw covenant protection.</p>',
    "42": '<p>"Their enemies oppressed them and subjected them to their power" — the experiential consequences of divine withdrawal: oppression (<em>wayyaʿăšûm ʾôyĕbêhem</em>) and subjugation. The root <em>ʿāšaq</em> (oppress, exploit) is the vocabulary of economic and social injustice — crushing those without power. The same word describes Israel\'s oppression in Egypt (Exod 3:9) and the oppression the Torah laws were designed to prevent (Lev 19:13; Deut 24:14). In the irony of the covenant: Israel, rescued from oppression in Egypt, experienced the same oppression from the nations when they abandoned the covenant that was supposed to make them different from the oppressors.</p>',
    "43": '<p>"Many times he delivered them, but they were bent on rebellion (<em>wĕhēmmāh yamrû bĕʿăṣātām</em>) and were brought low in their sin" — the repeated-deliverance summary. "Many times (<em>paʿamîm rabbôt</em>)" covers the entire Judges cycle: Othniel, Ehud, Deborah, Gideon, Jephthah, Samson — and beyond into the Samuel-Kings period. "Bent on rebellion (<em>yamrû bĕʿăṣātām</em>)" — stubbornly, by their own counsel, they rebelled (Ps 107:11 uses the same phrase). The pattern is not occasional failure but a structural orientation toward rebellion — a characteristic disposition that repeated deliverances failed to break. Paul reads this as evidence for the depth of human sinfulness requiring not repeated deliverance but fundamental transformation (Rom 7:14-25).</p>',
    "44": '<p>"But he took note of their distress when he heard their cry" — the pivot toward grace, after the long catalogue of failure. "Took note (<em>wayyarĕʾ</em> — he saw)" and "heard (<em>wayišmaʿ</em>)" — the same two verbs as Exod 2:24-25 when YHWH responded to Israel\'s groaning in Egypt: "God heard their groaning... God saw the Israelites and was concerned about them." The repetition of the Exodus pattern signals that the covenant\'s rescue mechanism operates not because of Israel\'s merit but because YHWH sees and hears the distress of his covenant people. The cry of distress consistently activates the covenant regardless of the preceding failure.</p>',
    "45": '<p>"For their sake he remembered his covenant and out of his great love he relented (<em>wayyinnāḥem kĕrōb ḥăsādāyw</em>)" — the pivotal verse of the entire psalm. YHWH\'s motivation for continuing to deliver a persistently rebellious people: (1) covenant memory — the Abrahamic/Mosaic covenant still structures his relationship to Israel; (2) great steadfast love (<em>rōb ḥăsādāyw</em> = the abundance of his covenantal loyalties). "He relented (<em>nāḥam</em>)" — the same verb as Gen 6:6 (YHWH "grieved/relented" that he had made humanity) and Exod 32:14 (YHWH "relented" from the disaster he had threatened after Moses\'s intercession). Divine relenting is not weakness or inconstancy but the covenant loyalty overcoming judgment.</p>',
    "46": '<p>"He caused all who held them captive to show them mercy (<em>wayyitten ʾôtām lĕraḥămîm liphĕnê kol-šôbêhem</em>)" — a remarkable verse: YHWH changes the hearts of the captors toward mercy. This is precisely what happened in the Babylonian exile: Cyrus of Persia issued his decree of return (Ezra 1:1-4; Isa 44:28-45:1 prophesied it). YHWH moved the hearts of foreign rulers to show mercy to Israel. "Mercy (<em>raḥămîm</em>)" — the deep compassion/womb-love of Ps 69:16 — applied here to what foreign rulers felt toward their captives. The mechanism: YHWH did not rescue Israel through military action but by softening the heart of those who held power over them.</p>',
    "47": '<p>"Save us, LORD our God, and gather us from the nations, to give thanks to your holy name and to glory in your praise" — the prayer that gives the whole psalm its purpose: the historical confession of failure (vv. 6-46) was preparation for this petition. The three elements of the prayer: (1) "save us (<em>hôšîʿēnû</em>)" — the Exodus salvation verb applied to the present exile situation; (2) "gather us from the nations (<em>qabĕṣēnû min-haggôyim</em>)" — the ingathering from exile (Deut 30:3-5; Isa 43:5; Jer 31:8-10); (3) the purpose: to give thanks and glorify. Restoration is not an end in itself but a means to renewed covenant worship. This verse places the psalm in the post-exilic period or in anticipation of exile.</p>',
    "48": '<p>"Praise be to the LORD, the God of Israel, from everlasting to everlasting. Let all the people say, \'Amen!\' Praise the LORD (<em>hallĕlû-yāh</em>)!" — the doxology that closes Book IV of the Psalter (Pss 90-106). Each of the five books ends with a doxology (Ps 41:13; 72:18-19; 89:52; 106:48; 150:6). "From everlasting to everlasting (<em>mēhāʿôlām wĕʿaḏ-hāʿôlām</em>)" — YHWH\'s existence spans both the remote past and the limitless future — his covenantal faithfulness is grounded in his eternal nature. "Let all the people say \'Amen!\'" — the congregational response, the community ratifying the doxology as its own confession. The double <em>Hallĕlû-yāh</em> (closing this psalm and opening Ps 107, which begins Book V) creates a liturgical seam in the Psalter.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-context', 'psalms', existing)
    print('Psalms 105-106 mkt-context written.')

if __name__ == '__main__':
    main()
